openclaw config schema 2>&1 | python3 -c "
import json,sys
schema = json.load(sys.stdin)
def print_props(obj, prefix=''):
    if not isinstance(obj, dict): return
    for k,v in obj.items():
        if isinstance(v, dict):
            if 'title' in v or 'description' in v:
                print(f'{prefix}{k}: {v.get(\"title\",\"\")} — {v.get(\"description\",\"\")[:120]}')
            if 'properties' in v:
                print_props(v['properties'], prefix + f'{k}.')
            elif v.get('type') == 'object' and 'anyOf' not in v:
                print_props(v, prefix + f'{k}.')
print_props(schema.get('properties',{}))
" | grep -i -E "context|compact|token|truncat|memory|bootstrap" | head -40

openclaw config schema 2>&1 | python3 -c "
import json,sys
schema = json.load(sys.stdin)
# Look for session, compaction, cleanup related
import re
def find(obj, path=''):
    if isinstance(obj, dict):
        for k,v in obj.items():
            newpath = f'{path}.{k}' if path else k
            if isinstance(v, str) and any(x in k.lower() for x in ['compact','cleanup','session','context','token','truncat']):
                print(newpath, '=', v)
            find(v, newpath)
    elif isinstance(obj, list):
        for i,v in enumerate(obj):
            find(v, f'{path}[{i}]')
find(schema)
" | head -80

