          "title": "Session Reset Mode",
          "description": "Selects reset strategy: \"daily\" resets at a configured hour and \"idle\" resets after inactivity windows. Keep one clear mode per policy to avoid surprising context turnover patterns."
        },
        "atHour": {
          "type": "integer",
          "minimum": 0,
          "maximum": 23,
          "title": "Session Daily Reset Hour",
          "description": "Sets local-hour boundary (0-23) for daily reset mode so sessions roll over at predictable times. Use with mode=daily and align to operator timezone expectations for human-readable behavior."
        },
        "idleMinutes": {
          "type": "integer",
          "exclusiveMinimum": 0,
          "maximum": 9007199254740991,
          "title": "Session Reset Idle Minutes",
