                "title": "Session Send Rule Action",
                "description": "Defines rule decision as \"allow\" or \"deny\" when the corresponding match criteria are satisfied. Use deny-first ordering when enforcing strict boundaries with explicit allow exceptions."
              },
              "match": {
                "type": "object",
                "properties": {
                  "channel": {
                    "type": "string",
                    "title": "Session Send Rule Channel",
                    "description": "Matches rule application to a specific channel/provider id (for example discord, telegram, slack). Use this when one channel should permit or deny delivery independently of others."
                  },
                  "chatType": {
                    "anyOf": [
                      {
                        "type": "string",
                        "const": "direct"
                      },
                      {
                        "type": "string",
                        "const": "group"
                      },
                      {
                        "type": "string",
                        "const": "channel"
                      },
                      {
                        "type": "string",
                        "const": "dm"
                      }
                    ],
                    "title": "Session Send Rule Chat Type",
                    "description": "Matches rule application to chat type (direct, group, thread) so behavior varies by conversation form. Use this when DM and group destinations require different safety boundaries."
                  },
                  "keyPrefix": {
                    "type": "string",
                    "title": "Session Send Rule Key Prefix",
                    "description": "Matches a normalized session-key prefix after internal key normalization steps in policy consumers. Use this for general prefix controls, and prefer rawKeyPrefix when exact full-key matching is required."
                  },
                  "rawKeyPrefix": {
                    "type": "string",
                    "title": "Session Send Rule Raw Key Prefix",
                    "description": "Matches the raw, unnormalized session-key prefix for exact full-key policy targeting. Use this when normalized keyPrefix is too broad and you need agent-prefixed or transport-specific precision."
                  }
                },
                "additionalProperties": false,
                "title": "Session Send Rule Match",
                "description": "Defines optional rule match conditions that can combine channel, chatType, and key-prefix constraints. Keep matches narrow so policy intent stays readable and debugging remains straightforward."
              }
            },
            "required": [
              "action"
            ],
            "additionalProperties": false
          },
          "title": "Session Send Policy Rules",
          "description": "Ordered allow/deny rules evaluated before the default action, for example `{ action: \"deny\", match: { channel: \"discord\" } }`. Put most specific rules first so broad rules do not shadow exceptions."
        }
      },
      "additionalProperties": false,
      "title": "Session Send Policy",
      "description": "Controls cross-session send permissions using allow/deny rules evaluated against channel, chatType, and key prefixes. Use this to fence where session tools can deliver messages in complex environments."
    },
    "writeLock": {
      "type": "object",
      "properties": {
        "acquireTimeoutMs": {
          "type": "integer",
          "exclusiveMinimum": 0,
          "maximum": 9007199254740991,
          "title": "Session Write Lock Acquire Timeout",
          "description": "Milliseconds to wait while acquiring a session transcript write lock before reporting the session as busy. Default: 60000; env override: OPENCLAW_SESSION_WRITE_LOCK_ACQUIRE_TIMEOUT_MS."
        },
        "staleMs": {
          "type": "integer",
          "exclusiveMinimum": 0,
          "maximum": 9007199254740991,
          "title": "Session Write Lock Stale Timeout",
          "description": "Milliseconds before an existing session transcript lock can be treated as stale and reclaimed. Default: 1800000; env override: OPENCLAW_SESSION_WRITE_LOCK_STALE_MS."
        },
        "maxHoldMs": {
          "type": "integer",
          "exclusiveMinimum": 0,
          "maximum": 9007199254740991,
          "title": "Session Write Lock Max Hold",
          "description": "Milliseconds a held in-process session transcript lock may remain held before the watchdog releases it. Default: 300000; env override: OPENCLAW_SESSION_WRITE_LOCK_MAX_HOLD_MS."
        }
      },
      "additionalProperties": false,
      "title": "Session Write Lock",
      "description": "Groups session transcript write-lock controls. Tune only when legitimate transcript prep, cleanup, compaction, or mirror work contends longer than the default policies."
    },
    "agentToAgent": {
      "type": "object",
      "properties": {
        "maxPingPongTurns": {
          "type": "integer",
          "minimum": 0,
          "maximum": 20,
          "title": "Agent-to-Agent Ping-Pong Turns",
          "description": "Max reply-back turns between requester and target agents during agent-to-agent exchanges (0-20, default 5). Use lower values to hard-limit chatter loops and preserve predictable run completion."
        }
      },
      "additionalProperties": false,
      "title": "Session Agent-to-Agent",
      "description": "Groups controls for inter-agent session exchanges, including loop prevention limits on reply chaining. Keep defaults unless you run advanced agent-to-agent automation with strict turn caps."
    },
    "threadBindings": {
      "type": "object",
      "properties": {
        "enabled": {
          "type": "boolean",
          "title": "Thread Binding Enabled",
          "description": "Global master switch for thread-bound session routing features and focused thread delivery behavior. Keep enabled for modern thread workflows unless you need to disable thread binding globally."
        },
        "idleHours": {
          "type": "number",
          "minimum": 0,
          "title": "Thread Binding Idle Timeout (hours)",
          "description": "Default inactivity window in hours for thread-bound sessions across providers/channels (0 disables idle auto-unfocus). Default: 24."
        },
        "maxAgeHours": {
          "type": "number",
          "minimum": 0,
          "title": "Thread Binding Max Age (hours)",
          "description": "Optional hard max age in hours for thread-bound sessions across providers/channels (0 disables hard cap). Default: 0."
        },
        "spawnSessions": {
          "type": "boolean",
          "title": "Thread-Bound Session Spawns",
          "description": "Global default gate for creating thread-bound work sessions from sessions_spawn and ACP thread spawns. Default: true when thread bindings are enabled."
        },
        "defaultSpawnContext": {
          "type": "string",
          "enum": [
            "isolated",
            "fork"
          ],
          "title": "Thread Spawn Context",
          "description": "Default native subagent context for thread-bound spawns. Use \"fork\" to start from the requester transcript or \"isolated\" for a clean child. Default: \"fork\"."
        }
      },
      "additionalProperties": false,
      "title": "Session Thread Bindings",
      "description": "Shared defaults for thread-bound session routing behavior across providers that support thread focus workflows. Configure global defaults here and override per channel only when behavior differs."
    },
    "maintenance": {
      "type": "object",
      "properties": {
        "mode": {
          "type": "string",
          "enum": [
            "enforce",
            "warn"
          ],
          "title": "Session Maintenance Mode",
          "description": "Determines whether maintenance policies are only reported (\"warn\") or actively applied (\"enforce\"). Keep \"warn\" during rollout and switch to \"enforce\" after validating safe thresholds."
        },
        "pruneAfter": {
          "anyOf": [
            {
              "type": "string"
            },
            {
              "type": "number"
            }
          ],
          "title": "Session Prune After",
          "description": "Removes entries older than this duration (for example `30d` or `12h`) during maintenance passes. Use this as the primary age-retention control and align it with data retention policy."
        },
        "pruneDays": {
          "type": "integer",
          "exclusiveMinimum": 0,
          "maximum": 9007199254740991,
          "title": "Session Prune Days (Deprecated)",
          "description": "Deprecated age-retention field kept for compatibility with legacy configs using day counts. Use session.maintenance.pruneAfter instead so duration syntax and behavior are consistent."
        },
        "maxEntries": {
          "type": "integer",
          "exclusiveMinimum": 0,
          "maximum": 9007199254740991,
          "title": "Session Max Entries",
          "description": "Caps total session entry count retained in the store to prevent unbounded growth over time. Use lower limits for constrained environments, or higher limits when longer history is required."
        },
        "rotateBytes": {
          "anyOf": [
            {
              "type": "string"
            },
            {
              "type": "number"
            }
          ],
          "title": "Deprecated Session Rotate Size",
          "description": "Deprecated and ignored. Do not use for `sessions.json` growth control; OpenClaw no longer creates automatic rotation backups, and \"openclaw doctor --fix\" removes this key."
        },
