          "anyOf": [
            {
              "type": "string"
            },
            {
              "type": "number"
            }
          ],
          "title": "Session Max Disk Budget",
          "description": "Optional per-agent sessions-directory disk budget (for example `500mb`). Use this to cap session storage per agent; when exceeded, warn mode reports pressure and enforce mode performs oldest-first cleanup."
        },
        "highWaterBytes": {
          "anyOf": [
            {
              "type": "string"
            },
            {
              "type": "number"
            }
          ],
          "title": "Session Disk High-water Target",
          "description": "Target size after disk-budget cleanup (high-water mark). Defaults to 80% of maxDiskBytes; set explicitly for tighter reclaim behavior on constrained disks."
        }
      },
