{
  "agents": {
    "defaults": {
      "bootstrapTotalMaxChars": 60000
    },
    "list": [
      {
        "contextTokens": 131072
      }
    ]
  },
  "session": {
    "resetByType": {
      "direct": {
        "mode": "idle",
        "idleMinutes": 120
      }
    }
  }
}
EOF
openclaw config patch --file /tmp/fix.json5
openclaw gateway restart
```

Note: the patch merges arrays by index, so this will set `contextTokens` on the first agent in `agents.list` (which is `main`).

